import pytest
import yaml
import math
from pathlib import Path
import sys

sys.path.insert(0, str(Path(__file__).parent.parent))

from astar import a_star
from graph import create_graph


@pytest.fixture
def fixtures_dir():
    return Path(__file__).parent / 'fixtures'


def load_fixture(fixture_path):
    with open(fixture_path) as f:
        return yaml.safe_load(f)


@pytest.fixture(params=[
    'simple_grid.yaml',
    'directed_graph.yaml',
    'no_path.yaml'
])
def fixture_data(request, fixtures_dir):
    return load_fixture(fixtures_dir / request.param)


def manhattan_distance(start, goal, positions):
    def heuristic(vertex):
        pos = positions.get(vertex.element())
        goal_pos = positions.get(goal.element())
        if pos is None or goal_pos is None:
            return 0
        return abs(pos[0] - goal_pos[0]) + abs(pos[1] - goal_pos[1])
    return heuristic


def euclidean_distance(start, goal, positions):
    def heuristic(vertex):
        pos = positions.get(vertex.element())
        goal_pos = positions.get(goal.element())
        if pos is None or goal_pos is None:
            return 0
        dx = pos[0] - goal_pos[0]
        dy = pos[1] - goal_pos[1]
        return math.sqrt(dx * dx + dy * dy)
    return heuristic


def zero_heuristic(start, goal, positions):
    def heuristic(vertex):
        return 0
    return heuristic


def test_astar_finds_path(fixture_data):
    graph, weight_mapping = create_graph(fixture_data['edges'])
    start = graph.get_vertex(fixture_data['start'])
    goal = graph.get_vertex(fixture_data['goal'])

    heuristic_type = fixture_data.get('heuristic_type', 'zero')
    positions = fixture_data.get('positions', {})

    if heuristic_type == 'manhattan':
        heuristic = manhattan_distance(start, goal, positions)
    elif heuristic_type == 'euclidean':
        heuristic = euclidean_distance(start, goal, positions)
    else:
        heuristic = zero_heuristic(start, goal, positions)

    path, path_length = a_star(graph, start, goal, heuristic)

    expected_path = fixture_data.get('expected_path', [])
    expected_length = fixture_data.get('expected_length', math.inf)

    if expected_path:
        assert len(path) > 0, "Expected a path but none was found"
        assert [v.element() for v in path] == expected_path
        assert path_length == expected_length
    else:
        assert path == []
        assert math.isinf(path_length)


def test_astar_start_equals_goal():
    edges = [('a', 'b'), ('b', 'c')]
    graph, _ = create_graph(edges)
    start = graph.get_vertex('a')

    def dummy_heuristic(v):
        return 0

    path, path_length = a_star(graph, start, start, dummy_heuristic)

    assert len(path) == 1
    assert path[0] == start
    assert path_length == 0


def test_astar_single_edge_path():
    edges = [('a', 'b')]
    graph, _ = create_graph(edges)
    start = graph.get_vertex('a')
    goal = graph.get_vertex('b')

    def dummy_heuristic(v):
        return 0

    path, path_length = a_star(graph, start, goal, dummy_heuristic)

    assert len(path) == 2
    assert [v.element() for v in path] == ['a', 'b']
    assert path_length == 1

